+            <button class="btn btn-outline-secondary btn-sm flex-fill" @onclick="ClearFilters">Clear Filters</button>
+        </div>
+    </aside>
+
+    @* ── Main Content ── *@
+    <main class="catalog-main">
+        @if (isLoading)
+        {
+            <div class="d-flex justify-content-center py-5">
+                <div class="spinner-border" role="status">
